1	const TOKEN_KEY = "auth-token";
2	
3	function getToken(): string | null {
4	  if (typeof window === "undefined") return null;
5	  return localStorage.getItem(TOKEN_KEY);
6	}
7	
8	export function setToken(token: string): void {
9	  localStorage.setItem(TOKEN_KEY, token);
10	}
11	
12	export function clearToken(): void {
13	  localStorage.removeItem(TOKEN_KEY);
14	}
15	
16	export class ApiError extends Error {
17	  status: number;
18	
19	  constructor(status: number, message: string) {
20	    super(message);
21	    this.name = "ApiError";
22	    this.status = status;
23	  }
24	}
25	
26	export interface PaginatedResponse<T> {
27	  data: T[];
28	  pagination: {
29	    page: number;
30	    pageSize: number;
31	    total: number;
32	    totalPages: number;
33	  };
34	}
35	
36	interface ApiFetchOptions extends Omit<RequestInit, "body"> {
37	  params?: Record<string, string | number | undefined>;
38	  body?: unknown;
39	}
40	
41	function buildUrl(baseUrl: string, params?: Record<string, string | number | undefined>): string {
42	  if (!params) return baseUrl;
43	
44	  const searchParams = new URLSearchParams();
45	  for (const [key, value] of Object.entries(params)) {
46	    if (value !== undefined) {
47	      searchParams.set(key, String(value));
48	    }
49	  }
50	
51	  const qs = searchParams.toString();
52	  if (qs) {
53	    return baseUrl + (baseUrl.includes("?") ? "&" : "?") + qs;
54	  }
55	  return baseUrl;
56	}
57	
58	export async function apiFetch<T = unknown>(
59	  url: string,
60	  options: ApiFetchOptions = {},
61	): Promise<T> {
62	  const token = getToken();
63	
64	  const headers = new Headers(options.headers);
65	
66	  // Only set Content-Type when there is a body and it's not already set
67	  if (options.body && !headers.has("Content-Type")) {
68	    headers.set("Content-Type", "application/json");
69	  }
70	
71	  if (token) {
72	    headers.set("Authorization", `Bearer ${token}`);
73	  }
74	
75	  const { params, ...fetchOptions } = options;
76	  const finalUrl = buildUrl(url, params);
77	
78	  // Auto-serialize object bodies to JSON
79	  const body =
80	    options.body && typeof options.body === "object" && !(options.body instanceof FormData) && !(options.body instanceof URLSearchParams) && !(options.body instanceof Blob) && !(options.body instanceof ArrayBuffer) && !(options.body instanceof ReadableStream)
81	      ? JSON.stringify(options.body)
82	      : options.body;
83	
84	  const response = await fetch(finalUrl, {
85	    ...fetchOptions,
86	    body: body as BodyInit | undefined,
87	    headers,
88	  });
89	
90	  if (response.status === 401) {
91	    clearToken();
92	    throw new ApiError(401, "Unauthorized");
93	  }
94	
95	  if (!response.ok) {
96	    let message = `Request failed with status ${response.status}`;
97	    try {
98	      const responseBody = await response.json();
99	      if (responseBody.error) message = responseBody.error;
100	      if (responseBody.message) message = responseBody.message;
101	    } catch {
102	      // ignore parse errors
103	    }
104	    throw new ApiError(response.status, message);
105	  }
106	
107	  // Handle 204 No Content
108	  if (response.status === 204) {
109	    return undefined as T;
110	  }
111	
112	  return response.json() as Promise<T>;
113	}
114	
115	export { getToken, TOKEN_KEY };
