1	"use client";
2	
3	import React, {
4	  createContext,
5	  useCallback,
6	  useContext,
7	  useEffect,
8	  useMemo,
9	  useState,
10	} from "react";
11	import { apiFetch, setToken, clearToken, getToken } from "./api-client";
12	
13	export type UserRole = "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE";
14	
15	export interface User {
16	  id: string;
17	  name: string;
18	  email: string;
19	  role: UserRole;
20	  avatar?: string;
21	  department: string;
22	  departmentId: string;
23	}
24	
25	interface LoginResponse {
26	  token: string;
27	  user: User;
28	}
29	
30	interface SessionResponse {
31	  user: User;
32	}
33	
34	const defaultUser: User = {
35	  id: "default-user-id",
36	  name: "张明",
37	  email: "zhangming@example.com",
38	  role: "EMPLOYEE",
39	  department: "技术部",
40	  departmentId: "dept-tech",
41	};
42	
43	interface AuthContextType {
44	  user: User;
45	  token: string | null;
46	  loading: boolean;
47	  login: (email: string, password: string) => Promise<void>;
48	  logout: () => void;
49	  setRole: (role: UserRole) => void;
50	  unreadNotifications: number;
51	  setUnreadNotifications: (n: number) => void;
52	}
53	
54	const AuthContext = createContext<AuthContextType | null>(null);
55	
56	export function AuthProvider({ children }: { children: React.ReactNode }) {
57	  const [user, setUser] = useState<User>(defaultUser);
58	  const [token, setTokenState] = useState<string | null>(null);
59	  const [loading, setLoading] = useState(true);
60	  const [unreadNotifications, setUnreadNotifications] = useState(0);
61	
62	  // Restore session on mount
63	  useEffect(() => {
64	    const storedToken = getToken();
65	    if (storedToken) {
66	      setTokenState(storedToken);
67	      apiFetch<SessionResponse>("/api/auth/session")
68	        .then((data) => {
69	          setUser(data.user);
70	        })
71	        .catch(() => {
72	          // Session invalid, use default user
73	          clearToken();
74	          setTokenState(null);
75	          setUser(defaultUser);
76	        })
77	        .finally(() => {
78	          setLoading(false);
79	        });
80	    } else {
81	      setLoading(false);
82	    }
83	  }, []);
84	
85	  const login = useCallback(async (email: string, password: string) => {
86	    const data = await apiFetch<LoginResponse>("/api/auth/login", {
87	      method: "POST",
88	      body: JSON.stringify({ email, password }),
89	    });
90	    setToken(data.token);
91	    setTokenState(data.token);
92	    setUser(data.user);
93	  }, []);
94	
95	  const logout = useCallback(() => {
96	    // Fire and forget the logout request
97	    apiFetch("/api/auth/logout", { method: "POST" }).catch(() => {
98	      // ignore errors
99	    });
100	    clearToken();
101	    setTokenState(null);
102	    setUser(defaultUser);
103	  }, []);
104	
105	  const setRole = useCallback(
106	    (role: UserRole) => {
107	      setUser((prev) => ({ ...prev, role }));
108	    },
109	    [],
110	  );
111	
112	  const value = useMemo<AuthContextType>(
113	    () => ({
114	      user,
115	      token,
116	      loading,
117	      login,
118	      logout,
119	      setRole,
120	      unreadNotifications,
121	      setUnreadNotifications,
122	    }),
123	    [user, token, loading, login, logout, setRole, unreadNotifications],
124	  );
125	
126	  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
127	}
128	
129	export function useAuth(): AuthContextType {
130	  const ctx = useContext(AuthContext);
131	  if (!ctx) {
132	    throw new Error("useAuth must be used within an AuthProvider");
133	  }
134	  return ctx;
135	}
