8	
9	interface Recommendation {
10	  modelId: string;
11	  score: number;
12	  reason: string;
13	}
14	
15	interface ModelInfo {
16	  id: string;
17	  brandName: string;
18	  modelName: string;
19	  category: string;
20	  stock?: number;
21	}
22	
23	export default function ApplyPage() {
24	  const router = useRouter();
25	  const { user } = useAuth();
26	  const [models, setModels] = useState<ModelInfo[]>([]);
27	  const [selectedModelId, setSelectedModelId] = useState("");
28	  const [reason, setReason] = useState("");
29	  const [requirement, setRequirement] = useState("");
30	  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
31	  const [recommending, setRecommending] = useState(false);
32	  const [recommendError, setRecommendError] = useState("");
33	  const [submitting, setSubmitting] = useState(false);
34	  const [submitError, setSubmitError] = useState("");
35	
36	  // Fetch available models on mount
37	  useEffect(() => {
38	    apiFetch<{ data: ModelInfo[] }>("/api/assets/mine", { params: { page: 1, pageSize: 1 } })
39	      .then(() => {
40	        // Not the right endpoint, skip fetching models for now
41	      })
42	      .catch(() => {});
43	    // We'll rely on the AI recommend to suggest models
44	  }, []);
45	
46	  const handleRecommend = async () => {
47	    if (!requirement.trim()) return;
48	    setRecommending(true);
49	    setRecommendError("");
50	    setRecommendations([]);
51	    try {
52	      const res = await apiFetch<{ ok: boolean; data: { recommendations: Recommendation[]; topPick: string } }>(
53	        "/api/ai/recommend",
54	        { method: "POST", body: { requirement } },
55	      );
56	      const data = res.ok ? res.data : (res as unknown as { recommendations: Recommendation[]; topPick: string });
57	      const recs = "recommendations" in data ? data.recommendations : (res as unknown as { recommendations: Recommendation[] }).recommendations;
58	      setRecommendations(recs ?? []);
59	      if (recs?.length > 0) {
60	        setSelectedModelId(recs[0].modelId);
61	      }
62	    } catch (err) {
63	      setRecommendError(err instanceof Error ? err.message : "推荐失败，请稍后重试");
64	    } finally {
65	      setRecommending(false);
66	    }
67	  };
68	
69	  const handleSubmit = async () => {
70	    if (!selectedModelId || !reason.trim()) return;
71	    setSubmitting(true);
72	    setSubmitError("");
73	    try {
74	      const ticket = await apiFetch<{ id: string }>("/api/tickets/apply", {
75	        method: "POST",
76	        body: { modelId: selectedModelId, reason },
77	      });
78	      router.push(`/tickets/${ticket.id}`);
79	    } catch (err) {
80	      setSubmitError(err instanceof Error ? err.message : "提交失败");
81	    } finally {
82	      setSubmitting(false);
83	    }
84	  };
85	
86	  return (
87	    <div className="flex flex-1 flex-col gap-6 p-4 max-w-2xl mx-auto w-full">
88	      <h1 className="text-2xl font-bold">申领设备</h1>
89	
90	      {/* AI Recommendation */}
91	      <div className="rounded-lg border p-4 space-y-3">
92	        <h2 className="font-semibold">AI 推荐</h2>
93	        <p className="text-sm text-muted-foreground">
94	          描述你的需求，AI 将推荐最适合的设备
95	        </p>
96	        <textarea
97	          value={requirement}
98	          onChange={(e) => setRequirement(e.target.value)}
99	          placeholder="例如：我需要一台用于日常开发的高性能笔记本电脑"
100	          rows={3}
101	          className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50"
102	        />
103	        <Button onClick={handleRecommend} disabled={recommending || !requirement.trim()}>
104	          {recommending ? "推荐中..." : "获取推荐"}
105	        </Button>
106	        {recommendError && (
107	          <p className="text-sm text-destructive">{recommendError}</p>
108	        )}
109	        {recommendations.length > 0 && (
110	          <div className="space-y-2 mt-2">
111	            <p className="text-sm font-medium">推荐结果：</p>
112	            {recommendations.map((r) => (
113	              <label
114	                key={r.modelId}
115	                className={`flex items-start gap-3 rounded-lg border p-3 cursor-pointer transition-colors ${
116	                  selectedModelId === r.modelId ? "border-primary bg-primary/5" : ""
117	                }`}
118	              >
119	                <input
120	                  type="radio"
121	                  name="model"
122	                  value={r.modelId}
123	                  checked={selectedModelId === r.modelId}
124	                  onChange={() => setSelectedModelId(r.modelId)}
125	                  className="mt-1"
126	                />
127	                <div className="flex-1">
128	                  <div className="flex items-center justify-between">
129	                    <span className="font-medium text-sm">型号 ID: {r.modelId}</span>
130	                    <span className="text-sm font-bold text-primary">{r.score}分</span>
131	                  </div>
132	                  <p className="text-sm text-muted-foreground mt-1">{r.reason}</p>
133	                </div>
134	              </label>
135	            ))}
136	          </div>
137	        )}
138	      </div>
139	
140	      {/* Submit Form */}
141	      <div className="rounded-lg border p-4 space-y-3">
142	        <h2 className="font-semibold">提交申请</h2>
143	        <div className="space-y-2">
144	          <label className="text-sm font-medium">选择设备</label>
145	          {recommendations.length === 0 ? (
146	            <div className="space-y-1">
147	              <p className="text-xs text-muted-foreground">
148	                请先使用 AI 推荐获取设备型号，或直接输入型号 ID
149	              </p>
150	              <input
151	                value={selectedModelId}
152	                onChange={(e) => setSelectedModelId(e.target.value)}
153	                placeholder="输入型号 ID"
154	                className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50"
155	              />
156	            </div>
157	          ) : (
158	            <p className="text-sm text-muted-foreground">
159	              已选择推荐列表中的设备
160	            </p>
161	          )}
162	        </div>
163	        <div className="space-y-2">
164	          <label className="text-sm font-medium">申请理由</label>
165	          <textarea
166	            value={reason}
167	            onChange={(e) => setReason(e.target.value)}
168	            placeholder="请说明申请理由..."
169	            rows={3}
170	            className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50"
171	          />
172	        </div>
173	        {submitError && (
174	          <p className="text-sm text-destructive">{submitError}</p>
175	        )}
176	        <Button onClick={handleSubmit} disabled={submitting || !selectedModelId || !reason.trim()}>
177	          {submitting ? "提交中..." : "提交申请"}
178	        </Button>
179	      </div>
180	    </div>
181	  );
182	}
