3	import { useAuth, type UserRole } from "@/lib/auth-context";
4	
5	interface RoleGuardProps {
6	  roles: UserRole[];
7	  children: React.ReactNode;
8	  fallback?: React.ReactNode;
9	}
10	
11	export function RoleGuard({
12	  roles,
13	  children,
14	  fallback = null,
15	}: RoleGuardProps) {
16	  const { user } = useAuth();
17	
18	  if (!roles.includes(user.role)) {
19	    return <>{fallback}</>;
20	  }
21	
22	  return <>{children}</>;
