1	import { NextRequest } from "next/server";
2	import { prisma } from "@/lib/prisma";
3	import { verifyAuth, AuthError, requireOneOf } from "@/lib/auth";
4	import { TicketWorkflow, WorkflowError } from "@/lib/ticket-workflow";
5	import { logTicketStatusChange } from "@/lib/audit";
6	import { notifyApprovalResult, notifyApprovalRequest } from "@/lib/notifications";
7	
8	export async function POST(
9	  request: NextRequest,
10	  { params }: { params: Promise<{ id: string }> },
11	) {
12	  try {
13	    const user = await verifyAuth(request);
14	    requireOneOf(user, "MANAGER", "IT_ADMIN");
15	
16	    const { id } = await params;
17	    const body = await request.json();
18	    const { deputy } = body;
19	
20	    const result = await prisma.$transaction(async (tx) => {
21	      const ticket = await tx.ticket.findUnique({
22	        where: { id },
23	        include: { applicant: true },
24	      });
25	      if (!ticket) {
26	        throw new WorkflowError("Ticket not found");
27	      }
28	
29	      const currentStatus = ticket.status as import("@prisma/client").TicketStatus;
30	
31	      // Determine who can approve at this stage
32	      if (currentStatus === "PENDING_MANAGER_1" || currentStatus === "PENDING_MANAGER_2") {
33	        const isIT = user.role === "IT_ADMIN";
34	        const isManager = user.role === "MANAGER";
35	
36	        if (isManager && !isIT) {
37	          // MANAGER must be in the same department as applicant
38	          const applicant = await tx.user.findUnique({
39	            where: { id: ticket.applicantId },
40	          });
41	          if (!applicant || applicant.deptId !== user.deptId) {
42	            throw new WorkflowError("You can only approve tickets for your own department");
43	          }
44	        }
45	
46	        if (isIT && deputy !== true) {
47	          throw new WorkflowError("IT_ADMIN can only approve as deputy (deputy: true)");
48	        }
49	      } else if (currentStatus === "PENDING_IT") {
50	        if (user.role !== "IT_ADMIN") {
51	          throw new WorkflowError("Only IT_ADMIN can approve at this stage");
52	        }
53	      } else {
54	        throw new WorkflowError(`Ticket cannot be approved in ${currentStatus} status`);
55	      }
56	
57	      const nextStatus = TicketWorkflow.nextOnApprove(
58	        ticket.type as import("@prisma/client").TicketType,
59	        currentStatus,
60	      );
61	      if (!nextStatus) {
62	        throw new WorkflowError("No valid approval target for this status");
63	      }
64	
65	      const updated = await tx.ticket.update({
66	        where: { id },
67	        data: {
68	          status: nextStatus,
69	          ...(deputy ? { deputyApproval: true, deputyApproverId: user.userId } : {}),
70	        },
71	      });
72	
73	      await logTicketStatusChange(tx, {
74	        ticketId: id,
75	        operatorId: user.userId,
76	        fromStatus: currentStatus,
77	        toStatus: nextStatus,
78	        metadata: { deputy: !!deputy },
79	      });
80	
81	      // Notify applicant
82	      await notifyApprovalResult(tx, {
83	        applicantId: ticket.applicantId,
84	        ticketId: id,
85	        approved: true,
86	        ticketType: ticket.type,
87	      });
88	
89	      // If moving to PENDING_IT after manager approval, notify IT (no specific notification needed here)
90	
91	      // If moving to PENDING_MANAGER_2 (transfer), notify the next manager
92	      if (nextStatus === "PENDING_MANAGER_2") {
93	        const dept = await tx.department.findUnique({
94	          where: { id: user.deptId },
95	          include: { manager: true },
96	        });
97	        if (dept?.manager) {
98	          await notifyApprovalRequest(tx, {
99	            managerId: dept.manager.id,
100	            ticketId: id,
101	            applicantName: "",
102	            ticketType: ticket.type,
103	          });
104	        }
105	      }
106	
107	      return updated;
108	    });
109	
110	    return Response.json(result);
111	  } catch (e) {
112	    if (e instanceof AuthError) {
113	      return Response.json({ error: e.message }, { status: e.statusCode });
114	    }
115	    if (e instanceof WorkflowError) {
116	      return Response.json({ error: e.message }, { status: 400 });
117	    }
118	    return Response.json({ error: "Internal server error" }, { status: 500 });
119	  }
120	}
