288	function ActionDialog({
289	  title,
290	  reason,
291	  setReason,
292	  onConfirm,
293	  onCancel,
294	  loading,
295	}: {
296	  title: string;
297	  reason: string;
298	  setReason: (v: string) => void;
299	  onConfirm: () => void;
300	  onCancel: () => void;
301	  loading: boolean;
302	}) {
303	  return (
304	    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
305	      <div className="w-full max-w-sm rounded-lg bg-background p-6 space-y-4">
306	        <h3 className="font-semibold">{title}</h3>
307	        <textarea
308	          value={reason}
309	          onChange={(e) => setReason(e.target.value)}
310	          placeholder="请输入原因..."
311	          rows={3}
312	          className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50"
313	        />
314	        <div className="flex justify-end gap-2">
315	          <Button variant="outline" onClick={onCancel}>取消</Button>
316	          <Button onClick={onConfirm} disabled={!reason.trim() || loading}>
317	            {loading ? "处理中..." : "确认"}
318	          </Button>
319	        </div>
320	      </div>
321	    </div>
322	  );
