1	export async function withAiFallback<T>(
2	  fn: () => Promise<T>,
3	  fallbackMessage: string,
4	): Promise<{ ok: true; data: T } | { ok: false; fallback: string }> {
5	  try {
6	    const data = await fn();
7	    return { ok: true, data };
8	  } catch (error) {
9	    console.error("[AI Fallback]", error);
10	    return { ok: false, fallback: fallbackMessage };
11	  }
12	}
